#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/common.sh";skip=false;serial=emulator-5554;while (($#));do case "$1" in --skip-build)skip=true;shift;;--serial)serial="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;if [[ "$skip" == false ]];then "$ARCHPHENE_SCRIPTS_DIR/build-install-kcalc-app.sh" --skip-install;fi;apk="$ARCHPHENE_ROOT/prototypes/kcalc-android-app/out/archpheneos-kcalc.apk";archphene_require_file "$apk";archphene_init_adb "$serial";package="$("$(archphene_android_tool "$(archphene_android_sdk)" build-tools/36.0.0/aapt2)" dump badging "$apk"|sed -n "s/package: name='\([^']*\)'.*/\1/p")";[[ -n "$package" ]] || archphene_die 'APK identity missing';archphene_adb_run install -r "$apk" >/dev/null;"$ARCHPHENE_SCRIPTS_DIR/test-kcalc-calculation.sh" --serial "$serial" --package "$package";archphene_note 'KCalc signed-package to signed-APK update transaction passed.'
